#pragma once

#include <cstdint>

// Use the real standard-library type when both the header and the feature are
// available.  This avoids adding a new name to namespace std (which is
// undefined behavior) while still providing a useful fallback for toolchains
// such as OpenHarmony's C++ runtime that do not ship <source_location>.

#if defined(__cpp_lib_source_location) && __cpp_lib_source_location >= 201907L
#  include <source_location>
#  define MBGL_HAS_STD_SOURCE_LOCATION 1
#elif __cplusplus >= 202002L && defined(__has_include) && __has_include(<source_location>)
#  include <source_location>
#  if defined(__cpp_lib_source_location) && __cpp_lib_source_location >= 201907L
#    define MBGL_HAS_STD_SOURCE_LOCATION 1
#  endif
#endif

namespace mbgl {

#if MBGL_HAS_STD_SOURCE_LOCATION

using SourceLocation = std::source_location;

#else

struct SourceLocation {
    const char* fileName_;
    const char* functionName_;
    std::uint_least32_t line_;
    std::uint_least32_t column_;

    constexpr SourceLocation() noexcept
        : fileName_(""), functionName_(""), line_(0), column_(0) {}

    constexpr SourceLocation(const char* fileName,
                             const char* functionName,
                             std::uint_least32_t line,
                             std::uint_least32_t column = 0) noexcept
        : fileName_(fileName), functionName_(functionName), line_(line), column_(column) {}

    constexpr const char* file_name() const noexcept { return fileName_; }
    constexpr const char* function_name() const noexcept { return functionName_; }
    constexpr std::uint_least32_t line() const noexcept { return line_; }
    constexpr std::uint_least32_t column() const noexcept { return column_; }

#if defined(__has_builtin) && __has_builtin(__builtin_FILE)
    static constexpr SourceLocation current(
        const char* file = __builtin_FILE(),
        const char* function = __builtin_FUNCTION(),
        std::uint_least32_t line = __builtin_LINE(),
        std::uint_least32_t column = __builtin_COLUMN()) noexcept {
        return SourceLocation(file, function, line, column);
    }
#endif
};

#endif

} // namespace mbgl

#if MBGL_HAS_STD_SOURCE_LOCATION
#  define MBGL_SOURCE_LOCATION_CURRENT() ::mbgl::SourceLocation::current()
#else
#  define MBGL_SOURCE_LOCATION_CURRENT() ::mbgl::SourceLocation(__FILE__, __func__, __LINE__)
#endif

